### Question A (14 Marks) `[KTU University Exam - Dec 2023]`

**Q. (a)** Write a C function to **create a singly circular linked list** of `n` nodes by inserting each new node at the **head**. Display the final list using a traversal function. **(7 marks)**

**Model Solution:**

```c
#include <stdio.h>
#include <stdlib.h>

struct Node {
    int data;
    struct Node *next;
};

// Function to insert at head of SCLL
struct Node* insertAtHead(struct Node *head, int value) {
    struct Node *newNode = (struct Node*)malloc(sizeof(struct Node));
    newNode->data = value;
    newNode->next = NULL;

    if (head == NULL) {
        newNode->next = newNode;   // Self-loop for 1-node list
        return newNode;
    }

    // Find the tail
    struct Node *temp = head;
    while (temp->next != head) {
        temp = temp->next;
    }
    newNode->next = head;
    temp->next = newNode;
    return newNode;
}

// Traversal function
void display(struct Node *head) {
    if (head == NULL) {
        printf("List is empty.\n");
        return;
    }
    struct Node *temp = head;
    printf("Circular List: ");
    do {
        printf("%d -> ", temp->data);
        temp = temp->next;
    } while (temp != head);
    printf("(back to %d)\n", head->data);
}

// Driver: create list of n nodes by repeated head insertion
int main() {
    struct Node *head = NULL;
    int n, x;
    printf("Enter number of nodes: ");
    scanf("%d", &n);
    for (int i = 0; i < n; i++) {
        printf("Enter value: ");
        scanf("%d", &x);
        head = insertAtHead(head, x);
    }
    display(head);
    return 0;
}
```

**Sample Run Trace:**

$$
\begin{aligned}
\text{Input } n = 4, \text{ values} = 10, 20, 30, 40 \\
\text{After inserting 10:} \quad & 10 \rightarrow 10 \\
\text{After inserting 20 at head:} \quad & 20 \rightarrow 10 \rightarrow 20 \\
\text{After inserting 30 at head:} \quad & 30 \rightarrow 20 \rightarrow 10 \rightarrow 30 \\
\text{After inserting 40 at head:} \quad & 40 \rightarrow 30 \rightarrow 20 \rightarrow 10 \rightarrow 40 \\
\text{Output:} \quad & 40 \rightarrow 30 \rightarrow 20 \rightarrow 10 \rightarrow (\text{back to } 40)
\end{aligned}
$$

